// Apply mutation to schedule.json.
const raw = $input.first().json;
const contentB64 = raw.content;
const sha = raw.sha;
const schedule = JSON.parse(Buffer.from(contentB64, 'base64').toString('utf8'));

const action = $('When Executed By Another Workflow').first().json.action || {};
const author  = $('When Executed By Another Workflow').first().json.author  || 'Bot';

let summary = '';

const shiftDate = (iso, days) => {
  if (!iso) return iso;
  const d = new Date(iso);
  d.setUTCDate(d.getUTCDate() + days);
  return d.toISOString().slice(0, 10);
};
const MONTHS = ['янв','фев','мар','апр','май','июн','июл','авг','сен','окт','ноя','дек'];
const fmtD = iso => { if (!iso) return '—'; const d = new Date(iso); return d.getUTCDate() + ' ' + MONTHS[d.getUTCMonth()]; };

if (action.type === 'mark_complete') {
  const t = schedule.tasks.find(x => x.id === String(action.taskId));
  if (!t) throw new Error('Task not found: ' + action.taskId);
  const date = action.date || new Date().toISOString().slice(0,10);
  t.actualEnd = date;
  if (!t.actualStart) t.actualStart = t.planStart || date;
  t.progress = 1;
  summary = `«${t.name}» — выполнена ${fmtD(date)}`;

} else if (action.type === 'mark_started') {
  const t = schedule.tasks.find(x => x.id === String(action.taskId));
  if (!t) throw new Error('Task not found: ' + action.taskId);
  const date = action.date || new Date().toISOString().slice(0,10);
  t.actualStart = date;
  if (typeof t.progress !== 'number' || t.progress === 0) t.progress = 0.01;
  summary = `«${t.name}» — начата ${fmtD(date)}`;

} else if (action.type === 'mark_cancelled') {
  const t = schedule.tasks.find(x => x.id === String(action.taskId));
  if (!t) throw new Error('Task not found: ' + action.taskId);
  t.cancelled = true;
  summary = `«${t.name}» — отменена`;

} else if (action.type === 'set_progress') {
  const t = schedule.tasks.find(x => x.id === String(action.taskId));
  if (!t) throw new Error('Task not found: ' + action.taskId);
  t.progress = Math.max(0, Math.min(1, Number(action.value)));
  summary = `«${t.name}» — прогресс ${Math.round(t.progress*100)}%`;

} else if (action.type === 'shift_dates') {
  const t = schedule.tasks.find(x => x.id === String(action.taskId));
  if (!t) throw new Error('Task not found: ' + action.taskId);
  const days = Number(action.days);
  const dt3 = action.dateType || 'plan';
  const shiftBothEnds = action.shiftStart !== false;
  if (dt3 === 'plan' || dt3 === 'both') {
    if (shiftBothEnds) t.planStart = shiftDate(t.planStart || t.start, days);
    t.planEnd = shiftDate(t.planEnd || t.end, days);
  }
  if (dt3 === 'actual' || dt3 === 'both') {
    if (shiftBothEnds) t.actualStart = shiftDate(t.actualStart || t.planStart || t.start, days);
    t.actualEnd = shiftDate(t.actualEnd || t.planEnd || t.end, days);
  }
  const dtLbl3 = dt3 === 'actual' ? 'факт' : dt3 === 'both' ? 'план и факт' : 'план';
  const _newEnd3 = (dt3==='actual'||dt3==='both') ? (t.actualEnd||t.planEnd) : t.planEnd;
  const _newSt3  = shiftBothEnds ? ((dt3==='actual'||dt3==='both') ? (t.actualStart||t.planStart) : t.planStart) : null;
  const _range3  = _newSt3 ? `${fmtD(_newSt3)} — ${fmtD(_newEnd3)}` : `→ ${fmtD(_newEnd3)}`;
  if (action.reason) {
    const delays = t.delays || [];
    delays.push({ date: new Date().toISOString().slice(0,10), days, reason: String(action.reason), dateType: dt3, shiftStart: shiftBothEnds });
    t.delays = delays;
  }
  summary = `«${t.name}» [${dtLbl3}]: ${days>0?'+':''}${days} дн. ${_range3}${action.reason ? ' · ' + action.reason : ''}`;

} else if (action.type === 'set_dates') {
  const t = schedule.tasks.find(x => x.id === String(action.taskId));
  if (!t) throw new Error('Task not found: ' + action.taskId);
  const dtS = action.dateType || 'plan';
  if (dtS === 'plan' || dtS === 'both') {
    if (action.planStart) t.planStart = action.planStart;
    if (action.planEnd)   t.planEnd   = action.planEnd;
  }
  if (dtS === 'actual' || dtS === 'both') {
    if (action.planStart) t.actualStart = action.planStart;
    if (action.planEnd)   t.actualEnd   = action.planEnd;
  }
  const dtLblS = dtS === 'actual' ? 'факт' : dtS === 'both' ? 'план и факт' : 'план';
  const _what = action.planStart && action.planEnd ? `${fmtD(action.planStart)} — ${fmtD(action.planEnd)}` : action.planEnd ? `конец → ${fmtD(action.planEnd)}` : `начало → ${fmtD(action.planStart)}`;
  summary = `«${t.name}» [${dtLblS}]: ${_what}`;

} else if (action.type === 'set_duration') {
  const t = schedule.tasks.find(x => x.id === String(action.taskId));
  if (!t) throw new Error('Task not found: ' + action.taskId);
  const dur = Number(action.duration);
  const newEnd = new Date(t.planStart || t.start);
  newEnd.setUTCDate(newEnd.getUTCDate() + dur);
  t.planEnd = newEnd.toISOString().slice(0, 10);
  summary = `«${t.name}» — длительность ${dur} дн., конец → ${fmtD(t.planEnd)}`;

} else if (action.type === 'bulk_shift_section') {
  const tasks = schedule.tasks.filter(t => t.section === action.section);
  const days = Number(action.days);
  const dtB = action.dateType || 'plan';
  const shiftBothB = action.shiftStart !== false;
  for (const t of tasks) {
    if (dtB === 'plan' || dtB === 'both') {
      if (shiftBothB) t.planStart = shiftDate(t.planStart || t.start, days);
      t.planEnd = shiftDate(t.planEnd || t.end, days);
    }
    if (dtB === 'actual' || dtB === 'both') {
      if (shiftBothB) t.actualStart = shiftDate(t.actualStart || t.planStart || t.start, days);
      t.actualEnd = shiftDate(t.actualEnd || t.planEnd || t.end, days);
    }
  }
  const dtLblB = dtB === 'actual' ? 'факт' : dtB === 'both' ? 'план и факт' : 'план';
  summary = `Раздел «${action.sectionName || action.section}» [${dtLblB}]: ${days>0?'+':''}${days} дн. — ${tasks.length} задач`;

} else if (action.type === 'add_delay') {
  const t = schedule.tasks.find(x => x.id === String(action.taskId));
  if (!t) throw new Error('Task not found: ' + action.taskId);
  const delays = t.delays || [];
  delays.push({ date: new Date().toISOString().slice(0,10), days: Number(action.days)||0, reason: String(action.reason||'') });
  t.delays = delays;
  summary = `«${t.name}» — задержка +${action.days||0} дн.${action.reason ? ': '+action.reason : ''}`;

} else if (action.type === 'add_note') {
  const t = schedule.tasks.find(x => x.id === String(action.taskId));
  if (!t) throw new Error('Task not found: ' + action.taskId);
  const notes = t.notes || [];
  notes.push({ date: new Date().toISOString().slice(0,10), text: String(action.note||'') });
  t.notes = notes;
  summary = `«${t.name}» — заметка добавлена`;

} else if (action.type === 'add_task') {
  const maxId = schedule.tasks.reduce((mx, t) => {
    const n = parseInt(t.id, 10);
    return isNaN(n) ? mx : Math.max(mx, n);
  }, 0);
  const newId = String(maxId + 1);
  schedule.tasks.push({
    id: newId,
    name: action.taskName,
    section: action.section,
    planStart: action.planStart,
    planEnd: action.planEnd,
    start: action.planStart,
    end: action.planEnd,
    progress: 0,
    contractor: action.contractorName || null,
    actualStart: null,
    actualEnd: null
  });
  summary = `Добавлена задача «${action.taskName}»`;

} else if (action.type === 'remove_task') {
  const idx = schedule.tasks.findIndex(t => t.id === String(action.taskId));
  if (idx === -1) throw new Error('Task not found: ' + action.taskId);
  const removed = schedule.tasks.splice(idx, 1)[0];
  summary = `Задача «${removed.name}» удалена`;

} else if (action.type === 'rename_task') {
  const t = schedule.tasks.find(x => x.id === String(action.taskId));
  if (!t) throw new Error('Task not found: ' + action.taskId);
  const oldName = t.name;
  t.name = action.newName;
  summary = `Переименовано: «${oldName}» → «${action.newName}»`;

} else if (action.type === 'move_task_section') {
  const t = schedule.tasks.find(x => x.id === String(action.taskId));
  if (!t) throw new Error('Task not found: ' + action.taskId);
  t.section = action.section;
  summary = `«${t.name}» перемещена в раздел ${action.section}`;

} else if (action.type === 'set_contractor') {
  const t = schedule.tasks.find(x => x.id === String(action.taskId));
  if (!t) throw new Error('Task not found: ' + action.taskId);
  t.contractor = action.contractorName;
  if (action.contractorPhone) t.contractorPhone = action.contractorPhone;
  summary = `«${t.name}» — подрядчик: ${action.contractorName}`;

} else if (action.type === 'set_section_contractor') {
  const tasks = schedule.tasks.filter(t => t.section === action.section);
  for (const t of tasks) { t.contractor = action.contractorName; }
  summary = `Раздел ${action.section}: подрядчик ${action.contractorName} (${tasks.length} задач)`;

} else if (action.type === 'add_section') {
  if (!schedule.sections) schedule.sections = [];
  if (schedule.sections.find(s => s.id === action.sectionId)) throw new Error('Section already exists: ' + action.sectionId);
  schedule.sections.push({ id: action.sectionId, name: action.sectionName, color: '#94a3b8' });
  summary = `Добавлен раздел «${action.sectionName}»`;

} else if (action.type === 'rename_section') {
  const sec = schedule.sections.find(s => s.id === action.sectionId);
  if (!sec) throw new Error('Section not found: ' + action.sectionId);
  sec.name = action.newName;
  summary = `Раздел переименован: «${action.oldName}» → «${action.newName}»`;

} else if (action.type === 'remove_section') {
  const idx = schedule.sections.findIndex(s => s.id === action.sectionId);
  if (idx === -1) throw new Error('Section not found: ' + action.sectionId);
  schedule.sections.splice(idx, 1);
  schedule.tasks = schedule.tasks.filter(t => t.section !== action.sectionId);
  summary = `Раздел «${action.sectionName}» удалён`;

} else if (action.type === 'add_milestone') {
  const ms = schedule.milestones || [];
  const id = 'M' + (ms.length + 1);
  ms.push({ id, date: action.date, name: action.name, stage: action.stage || 'ST4' });
  schedule.milestones = ms;
  summary = `add_milestone: ${action.name} on ${action.date}`;

} else {
  throw new Error('Unknown action type: ' + action.type);
}

// ─── История изменений (audit log): task.history[] + schedule.history[] ───
const histEntry = {
  at: new Date().toISOString(),
  by: author,
  type: action.type,
  summary
};
const pushToTask = (t) => {
  if (!t) return;
  t.history = t.history || [];
  t.history.push(histEntry);
};
const TASK_ACTIONS = new Set([
  'mark_complete','mark_started','mark_cancelled','set_progress',
  'shift_dates','set_dates','set_duration','add_delay','add_note',
  'rename_task','move_task_section','set_contractor'
]);
const SECTION_BULK = new Set(['bulk_shift_section','set_section_contractor']);
const PROJECT_ACTIONS = new Set([
  'add_task','remove_task','add_section','rename_section','remove_section','add_milestone'
]);

if (TASK_ACTIONS.has(action.type)) {
  pushToTask(schedule.tasks.find(x => x.id === String(action.taskId)));
} else if (SECTION_BULK.has(action.type)) {
  schedule.tasks.filter(x => x.section === action.section).forEach(pushToTask);
} else if (action.type === 'add_task') {
  pushToTask(schedule.tasks[schedule.tasks.length - 1]);
}
// Always mirror to project-level history (for remove_task + section/milestone + crash-proof audit)
if (PROJECT_ACTIONS.has(action.type) || TASK_ACTIONS.has(action.type) || SECTION_BULK.has(action.type)) {
  schedule.history = schedule.history || [];
  schedule.history.push(histEntry);
  // Cap to last 500 project-level entries to keep JSON reasonable
  if (schedule.history.length > 500) schedule.history = schedule.history.slice(-500);
}

schedule.project.lastUpdated   = new Date().toISOString();
schedule.project.lastUpdatedBy = author;

const newContent = Buffer.from(JSON.stringify(schedule, null, 2), 'utf8').toString('base64');

return [{ json: { sha, content: newContent, message: `bot: ${summary}`, committerName: author, committerEmail: 'bot@cyfr.ae', summary } }];

// Return structured result.
const r = $input.first().json;
const summary = $('Apply Mutation').first().json.summary;
return [{ json: {
  ok: true,
  commitSha: r.commit?.sha || null,
  commitUrl: r.commit?.html_url || null,
  summary
} }];
